+impl ConsumerRedeliveryDecisionSnapshot {
+    fn posterior(self) -> Posterior {
+        let exhausted = self.next_attempt > u32::from(self.max_deliver);
+        let pressured = self.pending_ratio_permille >= 850;
+        let weights = if exhausted {
+            [0.05, 0.1, 0.85]
+        } else if pressured {
